using Microsoft.JSInterop;

namespace sv_63ad80b527f1445a805dfd322fda1f4e.Components.Pages;

public sealed class NotepadInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/Pages/Notepad.razor.js";
    internal const string InitializeMethod = "initialize";
    internal const string SaveMethod = "save";
    internal const string ClearMethod = "clearStorage";
    internal const string SetDirtyMethod = "setDirty";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public NotepadInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask<string?> InitializeAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<string?>(InitializeMethod);
    }

    public async ValueTask SaveAsync(string content)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SaveMethod, content);
    }

    public async ValueTask ClearAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod);
    }

    public async ValueTask SetDirtyAsync(bool isDirty)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SetDirtyMethod, isDirty);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
    }
}

const STORAGE_KEY = "notepad-content";

let dirty = false;

function onBeforeUnload(e) {
    if (dirty) {
        e.preventDefault();
    }
}

export function initialize() {
    window.addEventListener("beforeunload", onBeforeUnload);
    return localStorage.getItem(STORAGE_KEY);
}

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
    dirty = false;
}

export function clearStorage() {
    localStorage.removeItem(STORAGE_KEY);
    dirty = false;
}

export function setDirty(isDirty) {
    dirty = isDirty;
}

export function dispose() {
    window.removeEventListener("beforeunload", onBeforeUnload);
}

@page "/notepad"
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea @bind="_content" @bind:event="oninput" @bind:after="OnContentChanged"
          rows="12" placeholder="Type your notes here..."></textarea>

<div class="toolbar">
    <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
    <button class="btn btn-outline-danger" @onclick="ClearAsync">Clear</button>
    @if (_lastSavedAt is not null)
    {
        <span class="save-status">Last saved at @_lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private const int AutoSaveIntervalMs = 30_000;

    private string _content = "";
    private DateTime? _lastSavedAt;
    private bool _isDirty;
    private NotepadInterop? _interop;
    private CancellationTokenSource _cts = new();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            var saved = await _interop.InitializeAsync();
            if (!string.IsNullOrEmpty(saved))
            {
                _content = saved;
                StateHasChanged();
            }

            _ = AutoSaveLoopAsync();
        }
    }

    private async Task AutoSaveLoopAsync()
    {
        try
        {
            while (!_cts.IsCancellationRequested)
            {
                await Task.Delay(AutoSaveIntervalMs, _cts.Token);
                if (_isDirty)
                {
                    await SaveAsync();
                    StateHasChanged();
                }
            }
        }
        catch (OperationCanceledException) { }
        catch (Exception ex) { await DispatchExceptionAsync(ex); }
    }

    private async Task OnContentChanged()
    {
        if (!_isDirty)
        {
            _isDirty = true;
            if (_interop is not null)
            {
                await _interop.SetDirtyAsync(true);
            }
        }
    }

    private async Task SaveNowAsync()
    {
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (_interop is not null)
        {
            await _interop.SaveAsync(_content);
            _isDirty = false;
            _lastSavedAt = DateTime.Now;
        }
    }

    private async Task ClearAsync()
    {
        _content = "";
        _isDirty = false;
        _lastSavedAt = null;
        if (_interop is not null)
        {
            await _interop.ClearAsync();
        }
    }

    public async ValueTask DisposeAsync()
    {
        _cts.Cancel();
        _cts.Dispose();

        if (_interop is not null)
        {
            await _interop.DisposeAsync();
        }
    }
}

